async function loadIncludes(){const t=Array.from(document.querySelectorAll("[data-include]"));0!==t.length&&await Promise.all(t.map(async t=>{const e=(t.getAttribute("data-include")||"").trim();if(e)try{const a=await fetch(e,{cache:"no-cache"});if(!a.ok)throw new Error(`HTTP ${a.status}`);const c=await a.text();t.innerHTML=c,t.removeAttribute("data-include")}catch(t){console.warn("Include failed:",e,t)}}))}window.__includesReady=loadIncludes();